fn clear_bss() {
    unsafe extern "C" {
        safe fn sbss();
        safe fn ebss();
    }
    unsafe {
        core::slice::from_raw_parts_mut(sbss as usize as *mut u8, ebss as usize - sbss as usize)
            .fill(0);
    }
}

use lazy_static::*;
use sync::UPIntrFreeCell;

lazy_static! {
    pub static ref DEV_NON_BLOCKING_ACCESS: UPIntrFreeCell<bool> =
        unsafe { UPIntrFreeCell::new(false) };
}

#[unsafe(no_mangle)]
pub fn rust_main() -> ! {
    clear_bss();
    logging::init();
    mm::init();
    arch::init_console();

    info!("KERN: skip gpu/input init for contest nographic qemu");
    // let _gpu = GPU_DEVICE.clone();
    // let _keyboard = KEYBOARD_DEVICE.clone();
    // let _mouse = MOUSE_DEVICE.clone();

    info!("KERN: init trap");
    arch::init_trap();
    arch::init_timer();

    board::device_init();

    fs::list_apps();
    let ext4_mode = fs::is_ext4();

    if ext4_mode {
        println!("[runner] EXT4 smoke test passed, runner flow reached");
        runner::run_first_stage();
        println!("[runner] EXT4 mode: skip legacy initproc bootstrap");
        arch::shutdown();
    }

    task::add_initproc();

    *DEV_NON_BLOCKING_ACCESS.exclusive_access() = true;

    task::run_tasks();

    panic!("Unreachable in rust_main!");
}

