fn pte_flags_string(bits: usize) -> String {
    let mut out = String::new();
    let mut first = true;
    for (mask, name) in [
        (1usize << 0, "V"),
        (1usize << 1, "R"),
        (1usize << 2, "W"),
        (1usize << 3, "X"),
        (1usize << 4, "U"),
        (1usize << 6, "A"),
        (1usize << 7, "D"),
    ] {
        if bits & mask != 0 {
            if !first {
                out.push('|');
            }
            out.push_str(name);
            first = false;
        }
    }
    if out.is_empty() {
        out.push_str("none");
    }
    out
}

fn trace_fault_pte(sepc: usize, stval: usize) {
    let va = crate::mm::VirtAddr::from(stval);
    let vpn = va.floor();
    if let Some(task) = crate::task::current_task() {
        let task_token = task.get_user_token();
        if let Some(process) = task.process.upgrade() {
            let pid = process.getpid();
            let inner = process.inner_exclusive_access();
            let exec_path = inner.exec_path.clone();
            let proc_token = inner.memory_set.token();
            let pte = inner.memory_set.translate(vpn);
            drop(inner);
            println!(
                "[fault-pte] pid={} path={} task_token=0x{:x} proc_token=0x{:x} sepc=0x{:x} stval=0x{:x}",
                pid, exec_path, task_token, proc_token, sepc, stval
            );
            match pte {
                Some(pte) => {
                    let flags = pte.bits & 0xff;
                    println!(
                        "[fault-pte] va=0x{:x} vpn=0x{:x} pte=0x{:x} ppn=0x{:x} flags={}",
                        stval,
                        vpn.0,
                        pte.bits,
                        pte.ppn().0,
                        pte_flags_string(flags)
                    );
                }
                None => println!(
                    "[fault-pte] va=0x{:x} vpn=0x{:x} pte=<not-found>",
                    stval, vpn.0
                ),
            }
        } else {
            println!(
                "[fault-pte] no-process task_token=0x{:x} sepc=0x{:x} stval=0x{:x} vpn=0x{:x}",
                task_token, sepc, stval, vpn.0
            );
        }
    } else {
        println!(
            "[fault-pte] no-current-task sepc=0x{:x} stval=0x{:x} vpn=0x{:x}",
            sepc, stval, vpn.0
        );
    }
}

#[unsafe(no_mangle)]
pub fn trap_handler() -> ! {
    set_kernel_trap_entry();
    let scause = scause::read();
    let stval = stval::read();
    // println!("into {:?}", scause.cause());
    match scause.cause() {
        Trap::Exception(Exception::UserEnvCall) => {
            // jump to next instruction anyway
            let mut cx = current_trap_cx();
            cx.sepc += 4;
            let syscall_id = cx.x[17];
            let syscall_args = [cx.x[10], cx.x[11], cx.x[12], cx.x[13], cx.x[14], cx.x[15]];

            enable_supervisor_interrupt();

            // get system call return value
            let result = syscall(syscall_id, syscall_args);
            // cx is changed during sys_exec, so we have to call it again
            cx = current_trap_cx();
            cx.x[10] = result as usize;
            crate::syscall::trace_current_syscall_context(
                "trap-syscall-return",
                syscall_id,
                Some(result),
            );
        }
        Trap::Exception(Exception::StoreFault)
        | Trap::Exception(Exception::StorePageFault)
        | Trap::Exception(Exception::InstructionFault)
        | Trap::Exception(Exception::InstructionPageFault)
        | Trap::Exception(Exception::LoadFault)
        | Trap::Exception(Exception::LoadPageFault) => {
            let cx = current_trap_cx();
            println!(
                "[trap] user fault cause={:?} sepc={:#x} stval={:#x} sp={:#x} gp={:#x} tp={:#x} a0={:#x} a1={:#x} a2={:#x} a3={:#x} a4={:#x} a5={:#x} a6={:#x} a7={:#x}",
                scause.cause(),
                cx.sepc,
                stval,
                cx.x[2],
                cx.x[3],
                cx.x[4],
                cx.x[10],
                cx.x[11],
                cx.x[12],
                cx.x[13],
                cx.x[14],
                cx.x[15],
                cx.x[16],
                cx.x[17],
            );
            if matches!(
                scause.cause(),
                Trap::Exception(Exception::InstructionPageFault)
                    | Trap::Exception(Exception::InstructionFault)
            ) {
                trace_fault_pte(cx.sepc, stval);
            }
            current_add_signal(SignalFlags::SIGSEGV);
        }
        Trap::Exception(Exception::IllegalInstruction) => {
            let cx = current_trap_cx();
            println!(
                "[trap] illegal instruction sepc={:#x} stval={:#x} sp={:#x} gp={:#x} tp={:#x} a0={:#x} a1={:#x} a2={:#x} a3={:#x} a4={:#x} a5={:#x} a6={:#x} a7={:#x}",
                cx.sepc,
                stval,
                cx.x[2],
                cx.x[3],
                cx.x[4],
                cx.x[10],
                cx.x[11],
                cx.x[12],
                cx.x[13],
                cx.x[14],
                cx.x[15],
                cx.x[16],
                cx.x[17],
            );
            current_add_signal(SignalFlags::SIGILL);
        }
        Trap::Interrupt(Interrupt::SupervisorTimer) => {
            set_next_trigger();
            check_timer();
            suspend_current_and_run_next();
        }
        Trap::Interrupt(Interrupt::SupervisorExternal) => {
            crate::board::irq_handler();
        }
        _ => {
            panic!(
                "Unsupported trap {:?}, stval = {:#x}!",
                scause.cause(),
                stval
            );
        }
    }
    // check signals
    if let Some((errno, msg)) = check_signals_of_current() {
        println!("[kernel] {}", msg);
        exit_current_and_run_next(errno);
    }
    trap_return();
}

