const AT_NULL: usize = 0;
const AT_PHDR: usize = 3;
const AT_PHENT: usize = 4;
const AT_PHNUM: usize = 5;
const AT_PAGESZ: usize = 6;
const AT_FLAGS: usize = 8;
const AT_ENTRY: usize = 9;
const AT_UID: usize = 11;
const AT_EUID: usize = 12;
const AT_GID: usize = 13;
const AT_EGID: usize = 14;
const AT_PLATFORM: usize = 15;
const AT_HWCAP: usize = 16;
const AT_CLKTCK: usize = 17;
const AT_SECURE: usize = 23;
const AT_BASE_PLATFORM: usize = 24;
const AT_RANDOM: usize = 25;
const AT_HWCAP2: usize = 26;
const AT_EXECFN: usize = 31;
const PT_LOAD: u32 = 1;
const PT_PHDR: u32 = 6;
const EXEC_STACK_TRACE: bool = true;
const USER_HEAP_STACK_GAP: usize = 0x20_0000;

fn read_u16_le(data: &[u8], off: usize) -> Option<u16> {
    data.get(off..off + 2)
        .map(|s| u16::from_le_bytes([s[0], s[1]]))
}

fn read_u32_le(data: &[u8], off: usize) -> Option<u32> {
    data.get(off..off + 4)
        .map(|s| u32::from_le_bytes([s[0], s[1], s[2], s[3]]))
}

fn read_u64_le(data: &[u8], off: usize) -> Option<u64> {
    data.get(off..off + 8)
        .map(|s| u64::from_le_bytes([s[0], s[1], s[2], s[3], s[4], s[5], s[6], s[7]]))
}

fn build_exec_auxv(
    elf_data: &[u8],
    random_ptr: usize,
    execfn_ptr: usize,
    platform_ptr: usize,
) -> Vec<(usize, usize)> {
    // Linux-like auxv for glibc startup.
    let mut out: Vec<(usize, usize)> = Vec::new();
    if elf_data.len() < 64 {
        out.push((AT_PAGESZ, PAGE_SIZE));
        out.push((AT_CLKTCK, 100));
        if random_ptr != 0 {
            out.push((AT_RANDOM, random_ptr));
        }
        if execfn_ptr != 0 {
            out.push((AT_EXECFN, execfn_ptr));
        }
        if platform_ptr != 0 {
            out.push((AT_PLATFORM, platform_ptr));
        }
        out.push((AT_NULL, 0));
        return out;
    }
    // ELF magic + class64 + little-endian
    if elf_data[0..4] != [0x7f, 0x45, 0x4c, 0x46] || elf_data[4] != 2 || elf_data[5] != 1 {
        out.push((AT_PAGESZ, PAGE_SIZE));
        out.push((AT_CLKTCK, 100));
        if random_ptr != 0 {
            out.push((AT_RANDOM, random_ptr));
        }
        if execfn_ptr != 0 {
            out.push((AT_EXECFN, execfn_ptr));
        }
        if platform_ptr != 0 {
            out.push((AT_PLATFORM, platform_ptr));
        }
        out.push((AT_NULL, 0));
        return out;
    }
    let e_entry = read_u64_le(elf_data, 24).unwrap_or(0) as usize;
    let e_phoff = read_u64_le(elf_data, 32).unwrap_or(0) as usize;
    let e_phentsize = read_u16_le(elf_data, 54).unwrap_or(56) as usize;
    let e_phnum = read_u16_le(elf_data, 56).unwrap_or(0) as usize;

    let mut at_phdr: usize = 0;
    for i in 0..e_phnum {
        let ph_off = e_phoff + i * e_phentsize;
        if ph_off + 56 > elf_data.len() {
            break;
        }
        let p_type = read_u32_le(elf_data, ph_off).unwrap_or(0);
        let p_offset = read_u64_le(elf_data, ph_off + 8).unwrap_or(0) as usize;
        let p_vaddr = read_u64_le(elf_data, ph_off + 16).unwrap_or(0) as usize;
        let p_filesz = read_u64_le(elf_data, ph_off + 32).unwrap_or(0) as usize;

        if p_type == PT_PHDR {
            at_phdr = p_vaddr;
            break;
        }
        if p_type == PT_LOAD && at_phdr == 0 && e_phoff >= p_offset && e_phoff < p_offset + p_filesz
        {
            at_phdr = p_vaddr + (e_phoff - p_offset);
        }
    }

    if at_phdr != 0 {
        out.push((AT_PHDR, at_phdr));
    }
    out.push((AT_PHENT, e_phentsize));
    out.push((AT_PHNUM, e_phnum));
    out.push((AT_PAGESZ, PAGE_SIZE));
    out.push((AT_FLAGS, 0));
    out.push((AT_ENTRY, e_entry));
    out.push((AT_UID, 0));
    out.push((AT_EUID, 0));
    out.push((AT_GID, 0));
    out.push((AT_EGID, 0));
    out.push((AT_SECURE, 0));
    out.push((AT_HWCAP, 0));
    out.push((AT_HWCAP2, 0));
    out.push((AT_CLKTCK, 100));
    out.push((AT_BASE_PLATFORM, 0));
    if platform_ptr != 0 {
        out.push((AT_PLATFORM, platform_ptr));
    }
    if random_ptr != 0 {
        out.push((AT_RANDOM, random_ptr));
    }
    if execfn_ptr != 0 {
        out.push((AT_EXECFN, execfn_ptr));
    }
    out.push((AT_NULL, 0));
    out
}

