pub fn resolve_path(base_dir: &str, path: &str) -> Result<String, FsError> {
    if path.is_empty() || !base_dir.starts_with('/') {
        return Err(FsError::InvalidPath);
    }

    let start = if path.starts_with('/') { "/" } else { base_dir };
    let mut parts = path_components(start)?;

    for component in path.split('/') {
        if component.is_empty() || component == "." {
            continue;
        }
        if component == ".." {
            let _ = parts.pop();
            continue;
        }
        parts.push(component);
    }

    Ok(build_absolute_path(parts.as_slice()))
}

fn path_components(path: &str) -> Result<Vec<&str>, FsError> {
    if !path.starts_with('/') {
        return Err(FsError::InvalidPath);
    }

    let mut parts = Vec::new();
    for component in path.split('/') {
        if component.is_empty() || component == "." {
            continue;
        }
        if component == ".." {
            let _ = parts.pop();
            continue;
        }
        parts.push(component);
    }

    Ok(parts)
}

fn build_absolute_path(parts: &[&str]) -> String {
    if parts.is_empty() {
        return String::from("/");
    }

    let mut path = String::new();
    for component in parts.iter() {
        path.push('/');
        path.push_str(component);
    }
    path
}

