fn parse_user_str_array(token: usize, mut ptr: *const usize) -> Result<Vec<String>, isize> {
    let mut out = Vec::new();
    if (ptr as usize) == 0 {
        return Ok(out);
    }
    loop {
        let Some(arg_str_ptr) = translated_ref_checked(token, ptr).copied() else {
            return Err(-EFAULT);
        };
        if arg_str_ptr == 0 {
            break;
        }
        let Some(arg) = translated_str_checked(token, arg_str_ptr as *const u8) else {
            return Err(-EFAULT);
        };
        out.push(arg);
        unsafe {
            ptr = ptr.add(1);
        }
    }
    Ok(out)
}

