    let bytes = value.as_bytes();
    let n = core::cmp::min(dst.len().saturating_sub(1), bytes.len());
    dst[..n].copy_from_slice(&bytes[..n]);
}

fn write_user_pod<T: Copy>(token: usize, ptr: *mut u8, value: &T) -> bool {
    let bytes = unsafe { slice::from_raw_parts(value as *const T as *const u8, size_of::<T>()) };
    let Some(chunks) = translated_byte_buffer_checked(token, ptr as *const u8, bytes.len()) else {
        return false;
    };
    let mut copied = 0usize;
    for chunk in chunks.into_iter() {
        if copied >= bytes.len() {
            break;
        }
        let n = core::cmp::min(chunk.len(), bytes.len() - copied);
        chunk[..n].copy_from_slice(&bytes[copied..copied + n]);
        copied += n;
    }
    copied == bytes.len()
}

fn write_user_zeroes(token: usize, ptr: *mut u8, len: usize) -> bool {
    let Some(chunks) = translated_byte_buffer_checked(token, ptr as *const u8, len) else {
        return false;
    };
    let mut remaining = len;
    for chunk in chunks.into_iter() {
        if remaining == 0 {
            break;
        }
        let n = core::cmp::min(chunk.len(), remaining);
        for byte in chunk[..n].iter_mut() {
            *byte = 0;
        }
        remaining -= n;
    }
    remaining == 0
}

