#[derive(Clone, Copy)]
pub enum Ext4Error {
    EmptyPath,
    InvalidPath,
    NotFound,
    SuperBlock(Ext4ReadError),
    GroupDesc(Ext4GroupDescError),
    Inode(Ext4InodeError),
}

impl core::fmt::Debug for Ext4Error {
    fn fmt(&self, f: &mut core::fmt::Formatter<'_>) -> core::fmt::Result {
        match self {
            Self::EmptyPath => write!(f, "empty EXT4 path"),
            Self::InvalidPath => write!(f, "invalid EXT4 absolute path"),
            Self::NotFound => write!(f, "EXT4 path not found"),
            Self::SuperBlock(err) => write!(f, "EXT4 superblock error: {:?}", err),
            Self::GroupDesc(err) => write!(f, "EXT4 group descriptor error: {:?}", err),
            Self::Inode(err) => write!(f, "EXT4 inode error: {:?}", err),
        }
    }
}

impl From<Ext4ReadError> for Ext4Error {
    fn from(value: Ext4ReadError) -> Self {
        Self::SuperBlock(value)
    }
}

impl From<Ext4GroupDescError> for Ext4Error {
    fn from(value: Ext4GroupDescError) -> Self {
        Self::GroupDesc(value)
    }
}

impl From<Ext4InodeError> for Ext4Error {
    fn from(value: Ext4InodeError) -> Self {
        Self::Inode(value)
    }
}

pub fn ext4_read_file(path: &str, max_len: usize) -> Result<Vec<u8>, Ext4Error> {
    let sb = Ext4SuperBlock::read()?;
    let gdt = Ext4GroupDescTable::read(&sb)?;
    let inode = find_inode_by_path(path, &sb, &gdt)?;
    inode
        .read_file_prefix(&sb, max_len)
        .map_err(Ext4Error::from)
}

pub fn ext4_list_dir(path: &str) -> Result<Vec<String>, Ext4Error> {
    let sb = Ext4SuperBlock::read()?;
    let gdt = Ext4GroupDescTable::read(&sb)?;
    let inode = find_inode_by_path(path, &sb, &gdt)?;
    let entries = inode.read_dir_entries(&sb)?;
    let mut names = Vec::new();

    for entry in entries.into_iter() {
        if entry.name == "." || entry.name == ".." {
            continue;
        }
        names.push(entry.name);
    }

    Ok(names)
}

pub fn ext4_metadata(path: &str) -> Result<FileMetadata, Ext4Error> {
    let sb = Ext4SuperBlock::read()?;
    let gdt = Ext4GroupDescTable::read(&sb)?;
    let inode = find_inode_by_path(path, &sb, &gdt)?;
    Ok(FileMetadata {
        mode: inode.mode as u32,
        size: inode.size_lo as u64,
        blocks: inode.blocks_lo as u64,
        nlink: inode.links_count as u32,
    })
}

pub fn ext4_read_link(path: &str) -> Result<String, Ext4Error> {
    let sb = Ext4SuperBlock::read()?;
    let gdt = Ext4GroupDescTable::read(&sb)?;
    let inode = find_inode_by_path(path, &sb, &gdt)?;
    inode.read_symlink_target(&sb).map_err(Ext4Error::from)
}

pub fn ext4_find_testcode_scripts(path: &str) -> Result<Vec<String>, Ext4Error> {
    let names = ext4_list_dir(path)?;
    let mut scripts = Vec::new();

    for name in names.into_iter() {
        if name.ends_with("_testcode.sh") {
            let mut full_path = String::from(path);
            if !full_path.ends_with('/') {
                full_path.push('/');
            }
            full_path.push_str(name.as_str());
            scripts.push(full_path);
        }
    }

    Ok(scripts)
}

fn find_inode_by_path(
    path: &str,
    sb: &Ext4SuperBlock,
    gdt: &Ext4GroupDescTable,
) -> Result<Ext4Inode, Ext4Error> {
    if path.is_empty() {
        return Err(Ext4Error::EmptyPath);
    }
    if !path.starts_with('/') {
        return Err(Ext4Error::InvalidPath);
    }

    let components = path_components(path)?;
    if components.is_empty() {
        return Err(Ext4Error::InvalidPath);
    }

    let mut current_path = String::from("/");
    let mut inode = Ext4Inode::load_root_for_path(sb, gdt, current_path.as_str())?;

    for component in components.iter() {
        let entry = inode
            .find_dir_entry(sb, component.as_str())?
            .ok_or(Ext4Error::NotFound)?;
        if current_path != "/" {
            current_path.push('/');
        }
        current_path.push_str(component.as_str());
        inode = Ext4Inode::load_with_path(entry.inode, sb, gdt, current_path.as_str())?;
    }

    Ok(inode)
}

fn path_components(path: &str) -> Result<Vec<String>, Ext4Error> {
    let mut components = Vec::new();

    for component in path.split('/') {
        if component.is_empty() {
            continue;
        }
        if component == "." || component == ".." {
            return Err(Ext4Error::InvalidPath);
        }
        components.push(String::from(component));
    }

    Ok(components)
}

