use core::cell::{RefCell, RefMut, UnsafeCell};
use core::ops::{Deref, DerefMut};
use lazy_static::*;
use riscv::register::sstatus;

/*
/// Wrap a static data structure inside it so that we are
/// able to access it without any `unsafe`.
///
/// We should only use it in uniprocessor.
///
/// In order to get mutable reference of inner data, call
/// `exclusive_access`.
pub struct UPSafeCell<T> {
    /// inner data
    inner: RefCell<T>,
}

unsafe impl<T> Sync for UPSafeCell<T> {}

impl<T> UPSafeCell<T> {
    /// User is responsible to guarantee that inner struct is only used in
    /// uniprocessor.
    pub unsafe fn new(value: T) -> Self {
        Self {
            inner: RefCell::new(value),
        }
    }
    /// Panic if the data has been borrowed.
    pub fn exclusive_access(&self) -> RefMut<'_, T> {
        self.inner.borrow_mut()
    }
}
*/

pub struct UPSafeCellRaw<T> {
    inner: UnsafeCell<T>,
}

unsafe impl<T> Sync for UPSafeCellRaw<T> {}

impl<T> UPSafeCellRaw<T> {
    pub unsafe fn new(value: T) -> Self {
        Self {
            inner: UnsafeCell::new(value),
        }
    }
    pub fn get_mut(&self) -> &mut T {
        unsafe { &mut (*self.inner.get()) }
    }
}

pub struct IntrMaskingInfo {
    nested_level: usize,
    sie_before_masking: bool,
}

lazy_static! {
    static ref INTR_MASKING_INFO: UPSafeCellRaw<IntrMaskingInfo> =
        unsafe { UPSafeCellRaw::new(IntrMaskingInfo::new()) };
}

impl IntrMaskingInfo {
    pub fn new() -> Self {
        Self {
            nested_level: 0,
            sie_before_masking: false,
        }
    }

    pub fn enter(&mut self) {
        let sie = sstatus::read().sie();
        unsafe {
            sstatus::clear_sie();
        }
        if self.nested_level == 0 {
            self.sie_before_masking = sie;
        }
        self.nested_level += 1;
    }

    pub fn exit(&mut self) {
        self.nested_level -= 1;
        if self.nested_level == 0 && self.sie_before_masking {
            unsafe {
                sstatus::set_sie();
            }
        }
    }
}

pub struct UPIntrFreeCell<T> {
    /// inner data
    inner: RefCell<T>,
}

unsafe impl<T> Sync for UPIntrFreeCell<T> {}

pub struct UPIntrRefMut<'a, T>(Option<RefMut<'a, T>>);

impl<T> UPIntrFreeCell<T> {
    pub unsafe fn new(value: T) -> Self {
        Self {
            inner: RefCell::new(value),
        }
    }

    /// Panic if the data has been borrowed.
    pub fn exclusive_access(&self) -> UPIntrRefMut<'_, T> {
        INTR_MASKING_INFO.get_mut().enter();
        UPIntrRefMut(Some(self.inner.borrow_mut()))
    }

    pub fn exclusive_session<F, V>(&self, f: F) -> V
    where
        F: FnOnce(&mut T) -> V,
    {
        let mut inner = self.exclusive_access();
        f(inner.deref_mut())
    }
}

impl<'a, T> Drop for UPIntrRefMut<'a, T> {
    fn drop(&mut self) {
        self.0 = None;
        INTR_MASKING_INFO.get_mut().exit();
    }
}

impl<'a, T> Deref for UPIntrRefMut<'a, T> {
    type Target = T;
    fn deref(&self) -> &Self::Target {
        self.0.as_ref().unwrap().deref()
    }
}
impl<'a, T> DerefMut for UPIntrRefMut<'a, T> {
    fn deref_mut(&mut self) -> &mut Self::Target {
        self.0.as_mut().unwrap().deref_mut()
    }
}

use super::UPIntrFreeCell;
use crate::task::TaskControlBlock;
use crate::task::{block_current_and_run_next, suspend_current_and_run_next};
use crate::task::{current_task, wakeup_task};
use alloc::{collections::VecDeque, sync::Arc};

pub trait Mutex: Sync + Send {
    fn lock(&self);
    fn unlock(&self);
}

pub struct MutexSpin {
    locked: UPIntrFreeCell<bool>,
}

impl MutexSpin {
    pub fn new() -> Self {
        Self {
            locked: unsafe { UPIntrFreeCell::new(false) },
        }
    }
}

impl Mutex for MutexSpin {
    fn lock(&self) {
        loop {
            let mut locked = self.locked.exclusive_access();
            if *locked {
                drop(locked);
                suspend_current_and_run_next();
                continue;
            } else {
                *locked = true;
                return;
            }
        }
    }

    fn unlock(&self) {
        let mut locked = self.locked.exclusive_access();
        *locked = false;
    }
}

pub struct MutexBlocking {
    inner: UPIntrFreeCell<MutexBlockingInner>,
}

pub struct MutexBlockingInner {
    locked: bool,
    wait_queue: VecDeque<Arc<TaskControlBlock>>,
}

impl MutexBlocking {
    pub fn new() -> Self {
        Self {
            inner: unsafe {
                UPIntrFreeCell::new(MutexBlockingInner {
                    locked: false,
                    wait_queue: VecDeque::new(),
                })
            },
        }
    }
}

impl Mutex for MutexBlocking {
    fn lock(&self) {
        let mut mutex_inner = self.inner.exclusive_access();
        if mutex_inner.locked {
            mutex_inner.wait_queue.push_back(current_task().unwrap());
            drop(mutex_inner);
            block_current_and_run_next();
        } else {
            mutex_inner.locked = true;
        }
    }

    fn unlock(&self) {
        let mut mutex_inner = self.inner.exclusive_access();
        assert!(mutex_inner.locked);
        if let Some(waking_task) = mutex_inner.wait_queue.pop_front() {
            wakeup_task(waking_task);
        } else {
            mutex_inner.locked = false;
        }
    }
}

use crate::drivers::BLOCK_DEVICE;
use alloc::sync::Arc;
use easy_fs::BLOCK_SZ;

const EXT4_SUPERBLOCK_OFFSET: usize = 1024;
const EXT4_SUPERBLOCK_SIZE: usize = 1024;
const EXT4_MAGIC: u16 = 0xEF53;
const EXT4_DESC_SIZE_MIN: u16 = 32;

#[derive(Clone, Debug)]
pub struct Ext4SuperBlock {
    pub magic: u16,
    pub inode_count: u32,
    pub block_count_lo: u32,
    pub log_block_size: u32,
    pub block_size: u32,
    pub blocks_per_group: u32,
    pub inodes_per_group: u32,
    pub inode_size: u16,
    pub desc_size: u16,
    pub first_data_block: u32,
}

#[derive(Clone, Copy, Debug)]
pub enum Ext4ReadError {
    InvalidMagic,
    UnsupportedBlockSize,
}

impl Ext4SuperBlock {
    pub fn read() -> Result<Self, Ext4ReadError> {
        let block_device = Arc::clone(&BLOCK_DEVICE);
        let mut raw = [0u8; EXT4_SUPERBLOCK_SIZE];
        let start_block = EXT4_SUPERBLOCK_OFFSET / BLOCK_SZ;
        let block_count = EXT4_SUPERBLOCK_SIZE / BLOCK_SZ;

        for i in 0..block_count {
            let mut buf = [0u8; BLOCK_SZ];
            block_device.read_block(start_block + i, &mut buf);
            let begin = i * BLOCK_SZ;
            raw[begin..begin + BLOCK_SZ].copy_from_slice(&buf);
        }

        let magic = u16::from_le_bytes(raw[0x38..0x3A].try_into().unwrap());
        let inode_count = u32::from_le_bytes(raw[0x00..0x04].try_into().unwrap());
        let block_count_lo = u32::from_le_bytes(raw[0x04..0x08].try_into().unwrap());
        let log_block_size = u32::from_le_bytes(raw[0x18..0x1C].try_into().unwrap());
        let blocks_per_group = u32::from_le_bytes(raw[0x20..0x24].try_into().unwrap());
        let inodes_per_group = u32::from_le_bytes(raw[0x28..0x2C].try_into().unwrap());
        let inode_size = u16::from_le_bytes(raw[0x58..0x5A].try_into().unwrap());
        let raw_desc_size = u16::from_le_bytes(raw[0xFE..0x100].try_into().unwrap());
        let desc_size = if raw_desc_size == 0 {
            EXT4_DESC_SIZE_MIN
        } else {
            raw_desc_size
        };
        let first_data_block = u32::from_le_bytes(raw[0x14..0x18].try_into().unwrap());
        let block_size = 1024u32
            .checked_shl(log_block_size)
            .ok_or(Ext4ReadError::UnsupportedBlockSize)?;

        if magic != EXT4_MAGIC {
            return Err(Ext4ReadError::InvalidMagic);
        }

        Ok(Self {
            magic,
            inode_count,
            block_count_lo,
            log_block_size,
            block_size,
            blocks_per_group,
            inodes_per_group,
            inode_size,
            desc_size,
            first_data_block,
        })
    }

    pub fn print_summary(&self) {
        println!("detected EXT4 filesystem");
        println!("EXT4 superblock loaded");
        println!("magic = 0x{:04x}", self.magic);
        println!("inode_count = {}", self.inode_count);
        println!("block_count_lo = {}", self.block_count_lo);
        println!("log_block_size = {}", self.log_block_size);
        println!("block_size = {}", self.block_size);
        println!("blocks_per_group = {}", self.blocks_per_group);
        println!("inodes_per_group = {}", self.inodes_per_group);
        println!("inode_size = {}", self.inode_size);
        println!("desc_size = {}", self.desc_size);
        println!("first_data_block = {}", self.first_data_block);
    }
}

