impl core::fmt::Debug for Ext4InodeError {
    fn fmt(&self, f: &mut core::fmt::Formatter<'_>) -> core::fmt::Result {
        match self {
            Self::InvalidInode => write!(f, "invalid inode number or missing group descriptor"),
            Self::InvalidInodeSize => write!(f, "invalid inode size"),
            Self::InvalidExtentHeader(magic) => {
                write!(f, "invalid extent header magic: 0x{:04x}", magic)
            }
            Self::NotDirectory(mode) => {
                write!(f, "inode is not a directory, mode = 0x{:04x}", mode)
            }
            Self::NotRegularFile(mode) => {
                write!(f, "inode is not a regular file, mode = 0x{:04x}", mode)
            }
            Self::NotSymlink(mode) => {
                write!(f, "inode is not a symbolic link, mode = 0x{:04x}", mode)
            }
            Self::UnsupportedFileType(mode) => {
                write!(f, "unsupported inode file type, mode = 0x{:04x}", mode)
            }
            Self::NotExtentInode => write!(f, "root inode does not use extents"),
            Self::UnsupportedExtentDepth(depth) => write!(f, "unsupported extent depth: {}", depth),
            Self::InvalidDirectoryEntry => write!(f, "invalid directory entry"),
            Self::ReadOverflow => write!(f, "inode byte offset overflow"),
            Self::GroupDesc(err) => write!(f, "group descriptor error: {:?}", err),
        }
    }
}

