impl BlockDevice for VirtIOBlock {
    fn read_block(&self, block_id: usize, buf: &mut [u8]) {
        self.virtio_blk
            .exclusive_access()
            .read_block(block_id, buf)
            .expect("Error when reading VirtIOBlk");
    }

    fn write_block(&self, block_id: usize, buf: &[u8]) {
        self.virtio_blk
            .exclusive_access()
            .write_block(block_id, buf)
            .expect("Error when writing VirtIOBlk");
    }

    fn handle_irq(&self) {
        self.virtio_blk.exclusive_session(|blk| {
            while let Ok(token) = blk.pop_used() {
                if let Some(condvar) = self.condvars.get(&token) {
                    condvar.signal();
                }
            }
        });
    }
}

impl VirtIOBlock {
    pub fn new() -> Self {
        let virtio_blk = unsafe {
            let header = &mut *(VIRTIO0 as *mut VirtIOHeader);

            UPIntrFreeCell::new(VirtIOBlk::<VirtioHal>::new(header).unwrap())
        };

        let mut condvars = BTreeMap::new();

        let channels = virtio_blk.exclusive_access().virt_queue_size();

        for i in 0..channels {
            let condvar = Condvar::new();
            condvars.insert(i, condvar);
        }

        Self {
            virtio_blk,
            condvars,
        }
    }
}

use crate::mm::{
    FrameTracker, PageTable, PhysAddr, PhysPageNum, StepByOne, VirtAddr, frame_alloc_more,
    frame_dealloc, kernel_token,
};
