const VIRTIO6: usize = 0x10006000;

struct VirtIOInputInner {
    virtio_input: VirtIOInput<'static, VirtioHal>,
    events: VecDeque<u64>,
}

struct VirtIOInputWrapper {
    inner: UPIntrFreeCell<VirtIOInputInner>,
    condvar: Condvar,
}

pub trait InputDevice: Send + Sync + Any {
    fn read_event(&self) -> u64;
    fn handle_irq(&self);
    fn is_empty(&self) -> bool;
}

lazy_static::lazy_static!(
    pub static ref KEYBOARD_DEVICE: Arc<dyn InputDevice> = match VirtIOInputWrapper::try_new(VIRTIO5, "keyboard") {
        Ok(device) => Arc::new(device),
        Err(()) => Arc::new(NullInputDevice::new("keyboard")),
    };
    pub static ref MOUSE_DEVICE: Arc<dyn InputDevice> = match VirtIOInputWrapper::try_new(VIRTIO6, "mouse") {
        Ok(device) => Arc::new(device),
        Err(()) => Arc::new(NullInputDevice::new("mouse")),
    };
);

impl VirtIOInputWrapper {
    pub fn try_new(addr: usize, name: &'static str) -> Result<Self, ()> {
        let virtio_input =
            match unsafe { VirtIOInput::<VirtioHal>::new(&mut *(addr as *mut VirtIOHeader)) } {
                Ok(device) => device,
                Err(err) => {
                    warn!("{} 初始化失败，已降级为无输入设备模式: {:?}", name, err);
                    return Err(());
                }
            };
        let inner = VirtIOInputInner {
            virtio_input,
            events: VecDeque::new(),
        };
        Ok(Self {
            inner: unsafe { UPIntrFreeCell::new(inner) },
            condvar: Condvar::new(),
        })
    }
}

impl InputDevice for VirtIOInputWrapper {
    fn is_empty(&self) -> bool {
        self.inner.exclusive_access().events.is_empty()
    }

    fn read_event(&self) -> u64 {
        loop {
            let mut inner = self.inner.exclusive_access();
            if let Some(event) = inner.events.pop_front() {
                return event;
            } else {
                let task_cx_ptr = self.condvar.wait_no_sched();
                drop(inner);
                schedule(task_cx_ptr);
            }
        }
    }

    fn handle_irq(&self) {
        let mut count = 0;
        let mut result = 0;
        self.inner.exclusive_session(|inner| {
            inner.virtio_input.ack_interrupt();
            while let Some(event) = inner.virtio_input.pop_pending_event() {
                count += 1;
                result = (event.event_type as u64) << 48
                    | (event.code as u64) << 32
                    | (event.value) as u64;
                inner.events.push_back(result);
            }
        });
        if count > 0 {
            self.condvar.signal();
        };
    }
}

struct NullInputDevice {
