        true
    }

    fn read_event(&self) -> u64 {
        warn!("{} 不可用，返回空输入事件", self.name);
        0
    }

    fn handle_irq(&self) {
        warn!("{} 不可用，忽略输入中断", self.name);
    }
}

use bitflags::*;

bitflags! {
    pub struct SignalFlags: u32 {
        const SIGINT    = 1 << 2;
        const SIGILL    = 1 << 4;
        const SIGABRT   = 1 << 6;
        const SIGFPE    = 1 << 8;
        const SIGKILL   = 1 << 9;
        const SIGSEGV   = 1 << 11;
        const SIGTERM   = 1 << 15;
        const SIGCHLD   = 1 << 17;
    }
}

impl SignalFlags {
    pub fn from_signum(signum: u32) -> Option<Self> {
        match signum {
            2 => Some(Self::SIGINT),
            4 => Some(Self::SIGILL),
            6 => Some(Self::SIGABRT),
            8 => Some(Self::SIGFPE),
            9 => Some(Self::SIGKILL),
            11 => Some(Self::SIGSEGV),
            15 => Some(Self::SIGTERM),
            17 => Some(Self::SIGCHLD),
            _ => None,
        }
    }

    pub fn as_signum(self) -> Option<usize> {
        match self {
            Self::SIGINT => Some(2),
            Self::SIGILL => Some(4),
            Self::SIGABRT => Some(6),
            Self::SIGFPE => Some(8),
            Self::SIGKILL => Some(9),
            Self::SIGSEGV => Some(11),
            Self::SIGTERM => Some(15),
            Self::SIGCHLD => Some(17),
            _ => None,
        }
    }

    pub fn check_error(&self) -> Option<(i32, &'static str)> {
        if self.contains(Self::SIGINT) {
            Some((-2, "Killed, SIGINT=2"))
        } else if self.contains(Self::SIGILL) {
            Some((-4, "Illegal Instruction, SIGILL=4"))
        } else if self.contains(Self::SIGABRT) {
            Some((-6, "Aborted, SIGABRT=6"))
        } else if self.contains(Self::SIGFPE) {
            Some((-8, "Erroneous Arithmetic Operation, SIGFPE=8"))
        } else if self.contains(Self::SIGKILL) {
            Some((-9, "Killed, SIGKILL=9"))
        } else if self.contains(Self::SIGSEGV) {
            Some((-11, "Segmentation Fault, SIGSEGV=11"))
        } else if self.contains(Self::SIGTERM) {
            Some((-15, "Terminated, SIGTERM=15"))
        } else {
            None
        }
    }
}

