}

/// A simple FIFO scheduler.
impl TaskManager {
    pub fn new() -> Self {
        Self {
            ready_queue: VecDeque::new(),
        }
    }
    pub fn add(&mut self, task: Arc<TaskControlBlock>) {
        self.ready_queue.push_back(task);
    }
    pub fn fetch(&mut self) -> Option<Arc<TaskControlBlock>> {
        self.ready_queue.pop_front()
    }
}

lazy_static! {
    pub static ref TASK_MANAGER: UPIntrFreeCell<TaskManager> =
        unsafe { UPIntrFreeCell::new(TaskManager::new()) };
    pub static ref PID2PCB: UPIntrFreeCell<BTreeMap<usize, Arc<ProcessControlBlock>>> =
        unsafe { UPIntrFreeCell::new(BTreeMap::new()) };
    pub static ref PID_EXIT_STATUS: UPIntrFreeCell<BTreeMap<usize, i32>> =
        unsafe { UPIntrFreeCell::new(BTreeMap::new()) };
    pub static ref BOOT_LAST_CHILD_PID: UPIntrFreeCell<Option<usize>> =
        unsafe { UPIntrFreeCell::new(None) };
    pub static ref GLOBAL_OVERLAY_DIRS: UPIntrFreeCell<BTreeSet<String>> =
        unsafe { UPIntrFreeCell::new(BTreeSet::new()) };
    pub static ref GLOBAL_OVERLAY_FILES: UPIntrFreeCell<BTreeMap<String, Vec<u8>>> =
        unsafe { UPIntrFreeCell::new(BTreeMap::new()) };
    pub static ref GLOBAL_OVERLAY_DELETED: UPIntrFreeCell<BTreeSet<String>> =
        unsafe { UPIntrFreeCell::new(BTreeSet::new()) };
}

pub fn add_task(task: Arc<TaskControlBlock>) {
    TASK_MANAGER.exclusive_access().add(task);
}

pub fn wakeup_task(task: Arc<TaskControlBlock>) {
    let mut task_inner = task.inner_exclusive_access();
    task_inner.task_status = TaskStatus::Ready;
    drop(task_inner);
    add_task(task);
}

pub fn fetch_task() -> Option<Arc<TaskControlBlock>> {
    TASK_MANAGER.exclusive_access().fetch()
}

pub fn pid2process(pid: usize) -> Option<Arc<ProcessControlBlock>> {
    let map = PID2PCB.exclusive_access();
    map.get(&pid).map(Arc::clone)
}

pub fn insert_into_pid2process(pid: usize, process: Arc<ProcessControlBlock>) {
    PID2PCB.exclusive_access().insert(pid, process);
}

pub fn remove_from_pid2process(pid: usize) {
    let mut map = PID2PCB.exclusive_access();
    if map.remove(&pid).is_none() {
        panic!("cannot find pid {} in pid2task!", pid);
    }
}

pub fn record_pid_exit_status(pid: usize, exit_code: i32) {
    PID_EXIT_STATUS.exclusive_access().insert(pid, exit_code);
}

pub fn take_pid_exit_status(pid: usize) -> Option<i32> {
    PID_EXIT_STATUS.exclusive_access().remove(&pid)
}

pub fn set_boot_last_child_pid(pid: usize) {
    *BOOT_LAST_CHILD_PID.exclusive_access() = Some(pid);
}

pub fn boot_last_child_pid() -> Option<usize> {
    *BOOT_LAST_CHILD_PID.exclusive_access()
}

pub fn snapshot_global_overlay() -> (
    BTreeSet<String>,
    BTreeMap<String, Vec<u8>>,
    BTreeSet<String>,
) {
    (
        GLOBAL_OVERLAY_DIRS.exclusive_access().clone(),
        GLOBAL_OVERLAY_FILES.exclusive_access().clone(),
        GLOBAL_OVERLAY_DELETED.exclusive_access().clone(),
    )
}

pub fn replace_global_overlay(
    dirs: &BTreeSet<String>,
    files: &BTreeMap<String, Vec<u8>>,
    deleted: &BTreeSet<String>,
) {
    let keep = |path: &str| path == "/mnt" || path.starts_with("/mnt/");
    *GLOBAL_OVERLAY_DIRS.exclusive_access() = dirs
        .iter()
        .filter(|path| keep(path.as_str()))
        .cloned()
        .collect();
    *GLOBAL_OVERLAY_FILES.exclusive_access() = files
        .iter()
        .filter(|(path, _)| keep(path.as_str()))
        .map(|(path, data)| (path.clone(), data.clone()))
        .collect();
    *GLOBAL_OVERLAY_DELETED.exclusive_access() = deleted
        .iter()
        .filter(|path| keep(path.as_str()))
        .cloned()
        .collect();
}

use super::__switch;
use super::{ProcessControlBlock, TaskContext, TaskControlBlock};
use super::{TaskStatus, fetch_task, take_pid_exit_status};
use crate::sync::UPIntrFreeCell;
