pub struct Processor {
    current: Option<Arc<TaskControlBlock>>,
    idle_task_cx: TaskContext,
}

impl Processor {
    pub fn new() -> Self {
        Self {
            current: None,
            idle_task_cx: TaskContext::zero_init(),
        }
    }
    fn get_idle_task_cx_ptr(&mut self) -> *mut TaskContext {
        &mut self.idle_task_cx as *mut _
    }
    pub fn take_current(&mut self) -> Option<Arc<TaskControlBlock>> {
        self.current.take()
    }
    pub fn current(&self) -> Option<Arc<TaskControlBlock>> {
        self.current.as_ref().map(Arc::clone)
    }
}

lazy_static! {
    pub static ref PROCESSOR: UPIntrFreeCell<Processor> =
        unsafe { UPIntrFreeCell::new(Processor::new()) };
}

const TASK_SWITCH_TRACE: bool = true;

fn trace_task_switch(stage: &str, task: &Arc<TaskControlBlock>) {
    if !TASK_SWITCH_TRACE {
        return;
    }

    if let Some(process) = task.process.upgrade() {
        let pid = process.getpid();
        let (exec_path, proc_token) = {
            let inner = process.inner_exclusive_access();
            (inner.exec_path.clone(), inner.memory_set.token())
        };
        let task_token = task.get_user_token();
        let (trap_va, sepc, a0, a7) = {
            let task_inner = task.inner_exclusive_access();
            let trap_va = task_inner
                .res
                .as_ref()
                .map(|res| res.trap_cx_user_va())
                .unwrap_or(0);
            let cx = task_inner.get_trap_cx();
            (trap_va, cx.sepc, cx.x[10], cx.x[17])
        };
        println!(
            "[sched][{}] pid={} exec_path={} task_token=0x{:x} proc_token=0x{:x} trap_cx=0x{:x} sepc=0x{:x} a7=0x{:x} a0=0x{:x}",
            stage, pid, exec_path, task_token, proc_token, trap_va, sepc, a7, a0
        );
    } else {
        println!("[sched][{}] no-process", stage);
    }
}

pub fn run_tasks() {
    loop {
        let mut processor = PROCESSOR.exclusive_access();
        if let Some(task) = fetch_task() {
            let idle_task_cx_ptr = processor.get_idle_task_cx_ptr();
            // access coming task TCB exclusively
            let next_task_cx_ptr = task.inner.exclusive_session(|task_inner| {
                task_inner.task_status = TaskStatus::Running;
                &task_inner.task_cx as *const TaskContext
            });
            trace_task_switch("run_tasks-switch_to", &task);
            processor.current = Some(task);
            // release processor manually
            drop(processor);
            unsafe {
                __switch(idle_task_cx_ptr, next_task_cx_ptr);
            }
        } else {
            println!("no tasks available in run_tasks");
        }
    }
}

pub fn run_tasks_until_pid_exit(pid: usize) -> Option<i32> {
    run_tasks_until_pid_exit_timeout(pid, 3000)
}

pub fn run_tasks_until_pid_exit_timeout(pid: usize, timeout_ms: usize) -> Option<i32> {
    let start_ms = get_time_ms();

    loop {
        if let Some(code) = take_pid_exit_status(pid) {
            return Some(code);
        }

        if get_time_ms().saturating_sub(start_ms) >= timeout_ms {
            return None;
        }

        check_timer();

        if let Some(code) = take_pid_exit_status(pid) {
            return Some(code);
        }

        if get_time_ms().saturating_sub(start_ms) >= timeout_ms {
            return None;
        }

        let mut processor = PROCESSOR.exclusive_access();
        if let Some(task) = fetch_task() {
            let idle_task_cx_ptr = processor.get_idle_task_cx_ptr();
            let next_task_cx_ptr = task.inner.exclusive_session(|task_inner| {
                task_inner.task_status = TaskStatus::Running;
                &task_inner.task_cx as *const TaskContext
            });
            trace_task_switch("wait4_timeout-switch_to", &task);
            processor.current = Some(task);
            drop(processor);
            unsafe {
                __switch(idle_task_cx_ptr, next_task_cx_ptr);
            }
        } else {
            drop(processor);

            check_timer();

            if let Some(code) = take_pid_exit_status(pid) {
                return Some(code);
            }

            if get_time_ms().saturating_sub(start_ms) >= timeout_ms {
                return None;
            }
        }
    }
}

pub fn take_current_task() -> Option<Arc<TaskControlBlock>> {
    PROCESSOR.exclusive_access().take_current()
}

pub fn current_task() -> Option<Arc<TaskControlBlock>> {
    PROCESSOR.exclusive_access().current()
}

pub fn current_process() -> Arc<ProcessControlBlock> {
    current_task().unwrap().process.upgrade().unwrap()
}

pub fn current_user_token() -> usize {
    let task = current_task().unwrap();
    task.get_user_token()
}

pub fn current_trap_cx() -> &'static mut TrapContext {
    current_task()
        .unwrap()
        .inner_exclusive_access()
        .get_trap_cx()
}

pub fn current_trap_cx_user_va() -> usize {
    current_task()
        .unwrap()
        .inner_exclusive_access()
        .res
        .as_ref()
        .unwrap()
        .trap_cx_user_va()
