pub fn suspend_current_and_run_next() {
    // There must be an application running.
    let task = take_current_task().unwrap();

    // ---- access current TCB exclusively
    let mut task_inner = task.inner_exclusive_access();
    let task_cx_ptr = &mut task_inner.task_cx as *mut TaskContext;
    // Change status to Ready
    task_inner.task_status = TaskStatus::Ready;
    drop(task_inner);
    // ---- release current TCB

    // push back to ready queue.
    add_task(task);
    // jump to scheduling cycle
    schedule(task_cx_ptr);
}

/// This function must be followed by a schedule
pub fn block_current_task() -> *mut TaskContext {
    let task = take_current_task().unwrap();
    let mut task_inner = task.inner_exclusive_access();
    task_inner.task_status = TaskStatus::Blocked;
    &mut task_inner.task_cx as *mut TaskContext
}

pub fn block_current_and_run_next() {
    let task_cx_ptr = block_current_task();
    schedule(task_cx_ptr);
}

/// Exit the current 'Running' task and run the next task in task list.
pub fn exit_current_and_run_next(exit_code: i32) {
    let task = take_current_task().unwrap();
    let mut task_inner = task.inner_exclusive_access();
    let process = task.process.upgrade().unwrap();
    let tid = task_inner.res.as_ref().unwrap().tid;
    // record exit code
    task_inner.exit_code = Some(exit_code);
    task_inner.res = None;
    // here we do not remove the thread since we are still using the kstack
    // it will be deallocated when sys_waittid is called
    drop(task_inner);
    drop(task);
    // however, if this is the main thread of current process
    // the process should terminate at once
    if tid == 0 {
        let pid = process.getpid();
        if pid == IDLE_PID {
            println!(
                "[kernel] Idle process exit with exit_code {} ...",
                exit_code
            );
            if exit_code != 0 {
                //crate::sbi::shutdown(255); //255 == -1 for err hint
                shutdown(true);
            } else {
                //crate::sbi::shutdown(0); //0 for success hint
                shutdown(false);
            }
        }
        record_pid_exit_status(pid, exit_code);
        remove_from_pid2process(pid);
        let mut process_inner = process.inner_exclusive_access();
        // mark this process as a zombie process
        process_inner.is_zombie = true;
        // record exit code of main process
        process_inner.exit_code = exit_code;
        if let Some(parent_weak) = process_inner.parent.as_ref() {
            if let Some(parent) = parent_weak.upgrade() {
                parent.inner_exclusive_access().signals |= SignalFlags::SIGCHLD;
            }
        }

        if !is_ext4() {
            // easy-fs path: move all child processes under init process
            let mut initproc_inner = INITPROC.inner_exclusive_access();
            for child in process_inner.children.iter() {
                child.inner_exclusive_access().parent = Some(Arc::downgrade(&INITPROC));
                initproc_inner.children.push(child.clone());
            }
        } else {
            // ext4 runner path: INITPROC is not bootstrapped in rust_main.
            // Skip INITPROC reparenting to avoid touching ROOT_INODE(initproc).
            println!("[task] ext4 mode: skip reparent to INITPROC");
        }

        // Flush shadow-backed writable fds so process-exit semantics match close().
        for fd in 0..process_inner.fd_table.len() {
            if !process_inner
                .fd_persist_table
                .get(fd)
                .copied()
                .unwrap_or(false)
                || process_inner.fd_dir_table.get(fd).copied().unwrap_or(false)
            {
                continue;
            }
            let path = process_inner.fd_path_table.get(fd).cloned().flatten();
            let data = process_inner.fd_data_table.get(fd).cloned().flatten();
            if let (Some(path), Some(data)) = (path, data) {
                if !process_inner.overlay_deleted.contains(path.as_str()) {
                    process_inner.overlay_files.insert(path, data);
                }
            }
        }
        if is_ext4() {
            process_inner.overlay_dirs.insert(String::from("/mnt"));
            process_inner.overlay_deleted.remove("/mnt");
            replace_global_overlay(
                &process_inner.overlay_dirs,
                &process_inner.overlay_files,
                &process_inner.overlay_deleted,
            );
        }

        // deallocate user res (including tid/trap_cx/ustack) of all threads
        // it has to be done before we dealloc the whole memory_set
        // otherwise they will be deallocated twice
        let mut recycle_res = Vec::<TaskUserRes>::new();
        for task in process_inner.tasks.iter().filter(|t| t.is_some()) {
            let task = task.as_ref().unwrap();
            let mut task_inner = task.inner_exclusive_access();
            if let Some(res) = task_inner.res.take() {
                recycle_res.push(res);
            }
        }
        // dealloc_tid and dealloc_user_res require access to PCB inner, so we
        // need to collect those user res first, then release process_inner
        // for now to avoid deadlock/double borrow problem.
        drop(process_inner);
        recycle_res.clear();

        let mut process_inner = process.inner_exclusive_access();
        process_inner.children.clear();
        // deallocate other data in user space i.e. program code/data section
        process_inner.memory_set.recycle_data_pages();
        // drop file descriptors
        process_inner.fd_table.clear();
        process_inner.fd_path_table.clear();
        process_inner.fd_dir_table.clear();
        process_inner.fd_size_table.clear();
        process_inner.fd_dir_cursor_table.clear();
        process_inner.fd_data_table.clear();
        process_inner.fd_offset_table.clear();
        process_inner.fd_persist_table.clear();
        process_inner.fd_append_table.clear();
        // Remove all tasks except for the main thread itself.
        // This is because we are still using the kstack under the TCB
        // of the main thread. This TCB, including its kstack, will be
        // deallocated when the process is reaped via waitpid.
        while process_inner.tasks.len() > 1 {
            process_inner.tasks.pop();
        }
    }
    drop(process);
    // we do not have to save task context
    let mut _unused = TaskContext::zero_init();
    schedule(&mut _unused as *mut _);
}

