    readable: bool,
    writable: bool,
    inner: UPIntrFreeCell<BufferedFileInner>,
}

struct BufferedFileInner {
    data: Vec<u8>,
    offset: usize,
}

impl BufferedFile {
    fn new(data: Vec<u8>, readable: bool, writable: bool) -> Self {
        Self {
            readable,
            writable,
            inner: unsafe { UPIntrFreeCell::new(BufferedFileInner { data, offset: 0 }) },
        }
