}

impl File for BufferedFile {
    fn readable(&self) -> bool {
        self.readable
    }

    fn writable(&self) -> bool {
        self.writable
    }

    fn read(&self, mut buf: UserBuffer) -> usize {
        if !self.readable {
            return 0;
        }
        let mut inner = self.inner.exclusive_access();
        let mut total = 0usize;
        for slice in buf.buffers.iter_mut() {
            if inner.offset >= inner.data.len() {
                break;
            }
            let remaining = inner.data.len() - inner.offset;
            let read_len = core::cmp::min(slice.len(), remaining);
            slice[..read_len].copy_from_slice(&inner.data[inner.offset..inner.offset + read_len]);
            inner.offset += read_len;
            total += read_len;
        }
        total
    }

    fn write(&self, buf: UserBuffer) -> usize {
        if !self.writable {
            return 0;
        }
        let mut inner = self.inner.exclusive_access();
        let mut total = 0usize;
        for slice in buf.buffers.iter() {
            let start = inner.offset;
            let end = start + slice.len();
            if end > inner.data.len() {
                inner.data.resize(end, 0);
            }
            inner.data[start..end].copy_from_slice(slice);
            inner.offset = end;
            total += slice.len();
        }
        total
    }
}

