    let mut out = String::new();
    let mut first = true;
    for (mask, name) in [
        (1usize << 0, "V"),
        (1usize << 1, "R"),
        (1usize << 2, "W"),
        (1usize << 3, "X"),
        (1usize << 4, "U"),
        (1usize << 6, "A"),
        (1usize << 7, "D"),
    ] {
        if bits & mask != 0 {
            if !first {
                out.push('|');
            }
            out.push_str(name);
            first = false;
        }
    }
    if out.is_empty() {
        out.push_str("none");
    }
    out
}

