}

const FUTEX_WAIT: usize = 0;
const FUTEX_WAKE: usize = 1;
const FUTEX_CMD_MASK: usize = 0x7f;

lazy_static! {
    static ref FUTEX_WAIT_QUEUES: UPIntrFreeCell<BTreeMap<(usize, usize), VecDeque<Arc<TaskControlBlock>>>> =
        unsafe { UPIntrFreeCell::new(BTreeMap::new()) };
}

fn futex_key(token: usize, uaddr: usize) -> (usize, usize) {
    (token, uaddr)
}

fn write_user_zeroes(token: usize, ptr: *mut u8, len: usize) -> bool {
    let Some(chunks) = translated_byte_buffer_checked(token, ptr as *const u8, len) else {
        return false;
    };
    let mut remaining = len;
    for chunk in chunks.into_iter() {
        if remaining == 0 {
            break;
        }
        let n = core::cmp::min(chunk.len(), remaining);
        for byte in chunk[..n].iter_mut() {
            *byte = 0;
        }
        remaining -= n;
    }
    remaining == 0
}

fn sleep_ms(ms: usize) -> isize {
    let expire_ms = get_time_ms() + ms;
    let Some(task) = current_task() else {
        return -EINVAL;
    };
    add_timer(expire_ms, task);
    block_current_and_run_next();
    0
}

fn timespec_to_ms(spec: TimeSpec) -> Option<usize> {
    if spec.tv_sec < 0 || spec.tv_nsec < 0 || spec.tv_nsec >= 1_000_000_000 {
        return None;
    }
    let sec = spec.tv_sec as u64;
    let nsec = spec.tv_nsec as u64;
    Some(
        sec.saturating_mul(1000)
            .saturating_add(nsec / 1_000_000)
            .min(usize::MAX as u64) as usize,
    )
}

pub fn sys_sleep(req_or_ms: usize, rem: usize) -> isize {
    // Keep compatibility with the original oskernel userland, which passes a raw
    // millisecond integer, while also supporting Linux-like nanosleep(TimeVal*).
    if rem == 0 && req_or_ms < (1 << 20) {
        let ret = sleep_ms(req_or_ms);
        println!("[syscall] nanosleep ms={} => {}", req_or_ms, ret);
        return ret;
    }
    if req_or_ms == 0 {
        println!("[syscall] nanosleep => 0(zero)");
        return 0;
    }
    let token = current_user_token();
    let Some(req) = translated_ref_checked(token, req_or_ms as *const TimeSpec).copied() else {
        println!("[syscall] nanosleep => {}(bad-req)", -EFAULT);
        return -EFAULT;
    };
    let ms = match timespec_to_ms(req) {
        Some(ms) => ms,
        None => {
            println!(
                "[syscall] nanosleep sec={} nsec={} => {}(invalid-timespec)",
                req.tv_sec, req.tv_nsec, -EINVAL
            );
            return -EINVAL;
        }
    };
    let ret = sleep_ms(ms);
    if rem != 0 {
        if !write_user_zeroes(token, rem as *mut u8, core::mem::size_of::<TimeSpec>()) {
            println!("[syscall] nanosleep => {}(bad-rem)", -EFAULT);
            return -EFAULT;
        }
    }
    println!(
        "[syscall] nanosleep sec={} nsec={} => {}",
        req.tv_sec, req.tv_nsec, ret
    );
    ret
}

pub fn sys_clock_nanosleep(clock_id: usize, flags: usize, req: *const u8, rem: *mut u8) -> isize {
    if req.is_null() {
        println!(
            "[syscall] clock_nanosleep clk={} flags=0x{:x} => {}(null-req)",
            clock_id, flags, -EFAULT
        );
        return -EFAULT;
    }
    if !compat::sys_clock_nanosleep_flags_supported(flags) {
        println!(
            "[syscall] clock_nanosleep clk={} flags=0x{:x} => {}(flags)",
            clock_id, flags, -EINVAL
        );
        return -EINVAL;
    }
    let token = current_user_token();
    let Some(req_spec) = translated_ref_checked(token, req as *const TimeSpec).copied() else {
        println!(
            "[syscall] clock_nanosleep clk={} flags=0x{:x} => {}(bad-req)",
            clock_id, flags, -EFAULT
        );
        return -EFAULT;
    };
    let mut ms = match timespec_to_ms(req_spec) {
        Some(ms) => ms,
        None => {
            println!(
                "[syscall] clock_nanosleep clk={} sec={} nsec={} => {}(invalid-timespec)",
                clock_id, req_spec.tv_sec, req_spec.tv_nsec, -EINVAL
            );
            return -EINVAL;
        }
    };
    if (flags & 1) != 0 {
        let now_ms = get_time_ms();
        ms = ms.saturating_sub(now_ms);
    }
    let ret = sleep_ms(ms);
    if !rem.is_null() {
        if !write_user_zeroes(token, rem as *mut u8, core::mem::size_of::<TimeSpec>()) {
            println!(
                "[syscall] clock_nanosleep clk={} => {}(bad-rem)",
                clock_id, -EFAULT
            );
            return -EFAULT;
        }
    }
    println!(
        "[syscall] clock_nanosleep clk={} flags=0x{:x} sec={} nsec={} => {}",
        clock_id, flags, req_spec.tv_sec, req_spec.tv_nsec, ret
    );
    ret
}

