use super::{EINVAL, ENOMEM};
use crate::config::PAGE_SIZE;
use crate::mm::{MapPermission, MemorySet, VirtAddr};
use crate::task::{current_process, current_task};
use core::arch::asm;

const SYSCALL_TRACE: bool = true;
const PROT_READ: usize = 0x1;
const PROT_WRITE: usize = 0x2;
const PROT_EXEC: usize = 0x4;
const USER_HEAP_STACK_GAP: usize = 0x20_0000;

fn align_up(addr: usize) -> usize {
    (addr + PAGE_SIZE - 1) & !(PAGE_SIZE - 1)
}

fn align_down(addr: usize) -> usize {
    addr & !(PAGE_SIZE - 1)
}

fn is_page_aligned(addr: usize) -> bool {
    addr == align_down(addr)
}

fn range_mapped(memory_set: &MemorySet, start: usize, end: usize) -> bool {
    let mut cursor = align_down(start);
    let end_aligned = align_up(end);
    while cursor < end_aligned {
        if memory_set
            .translate(VirtAddr::from(cursor).floor())
            .is_some()
        {
            return true;
        }
        cursor = cursor.saturating_add(PAGE_SIZE);
    }
    false
}

fn find_free_mmap_range(
    preferred_start: usize,
    len: usize,
    program_brk: usize,
    memory_set: &MemorySet,
) -> Option<usize> {
    let heap_guard_end = align_up(program_brk.max(1));
    let mut candidate = align_up(preferred_start.max(heap_guard_end + PAGE_SIZE));
    let map_len = align_up(len);
    for _ in 0..4096 {
        let end = candidate.checked_add(map_len)?;
        if !range_mapped(memory_set, candidate, end) {
            return Some(candidate);
        }
        candidate = candidate.saturating_add(PAGE_SIZE);
    }
    None
}

fn flush_current_user_tlb() {
    unsafe {
        asm!("sfence.vma");
    }
}

pub fn sys_brk(brk: usize) -> isize {
    let process = current_process();
    let Some(task) = current_task() else {
        return -ENOMEM;
    };
    let heap_limit = {
        let task_inner = task.inner_exclusive_access();
        task_inner
            .res
            .as_ref()
            .map(|res| res.ustack_base())
            .unwrap_or(usize::MAX)
    };
    let heap_base = heap_limit.saturating_sub(USER_HEAP_STACK_GAP);
    let mut inner = process.inner_exclusive_access();
    if inner.program_brk == 0 {
        inner.program_brk = heap_base;
    }
    let old_brk = inner.program_brk;
    if brk == 0 {
        if SYSCALL_TRACE {
            println!("[syscall] brk brk=0x{:x} => 0x{:x}", brk, old_brk);
        }
        return old_brk as isize;
    }
    if brk >= heap_limit {
        if SYSCALL_TRACE {
            println!(
                "[syscall] brk brk=0x{:x} => 0x{:x} (reject: cross user stack 0x{:x})",
                brk, old_brk, heap_limit
            );
        }
        return old_brk as isize;
    }
    if brk > old_brk {
        let map_start = align_up(old_brk);
        let map_end = align_up(brk);
        if map_end > map_start {
            inner.memory_set.insert_framed_area(
                VirtAddr::from(map_start),
                VirtAddr::from(map_end),
                MapPermission::R | MapPermission::W | MapPermission::U,
            );
        }
    }
    if brk >= heap_base {
        inner.program_brk = brk;
    }
    if SYSCALL_TRACE {
        println!("[syscall] brk brk=0x{:x} => 0x{:x}", brk, inner.program_brk);
    }
    inner.program_brk as isize
}

pub fn sys_mprotect(start: usize, len: usize, prot: usize) -> isize {
    if start == 0 || len == 0 || !is_page_aligned(start) {
        return -EINVAL;
