    if align_up(end) <= start {
        return -EINVAL;
    }
    if SYSCALL_TRACE {
        println!(
            "[syscall] mprotect start=0x{:x} len={} prot=0x{:x} => 0",
            start, len, prot
        );
    }
    flush_current_user_tlb();
    0
}

