    } else {
        preferred_start
    };
    let Some(raw_end) = map_start.checked_add(len) else {
        if SYSCALL_TRACE {
            println!(
                "[syscall] mmap start=0x{:x} len={} => {}(overflow)",
                start, len, -ENOMEM
            );
        }
        return -ENOMEM;
    };
    let map_end = align_up(raw_end);
    if map_end <= map_start {
        if SYSCALL_TRACE {
            println!(
                "[syscall] mmap start=0x{:x} len={} => {}(bad-range)",
                start, len, -EINVAL
            );
        }
        return -EINVAL;
    }
    let heap_guard_end = align_up(inner.program_brk.max(1));
    if map_start < heap_guard_end {
        if SYSCALL_TRACE {
            println!(
                "[syscall] mmap start=0x{:x} len={} => {}(overlap-brk)",
                start, len, -ENOMEM
            );
        }
        return -ENOMEM;
    }
    if start != 0 && range_mapped(&inner.memory_set, map_start, map_end) {
        if SYSCALL_TRACE {
            println!(
                "[syscall] mmap start=0x{:x} len={} => {}(overlap-area)",
                start, len, -ENOMEM
            );
        }
        return -ENOMEM;
    }
    let mut map_perm = MapPermission::U;
    if (prot & PROT_READ) != 0 {
        map_perm |= MapPermission::R;
    }
    if (prot & PROT_WRITE) != 0 {
        map_perm |= MapPermission::W;
    }
    if (prot & PROT_EXEC) != 0 {
        map_perm |= MapPermission::X;
    }
    if map_perm == MapPermission::U {
        map_perm |= MapPermission::R;
    }
    inner.memory_set.insert_framed_area(
        VirtAddr::from(map_start),
        VirtAddr::from(map_end),
        map_perm,
    );
    inner.mmap_next = align_up(map_end + PAGE_SIZE);
    drop(inner);
    flush_current_user_tlb();
    if SYSCALL_TRACE {
        println!(
            "[syscall] mmap start=0x{:x} len={} prot=0x{:x} fd={} off={} => 0x{:x}",
            start, len, prot, _fd, _offset, map_start
        );
    }
    map_start as isize
}

