use log::{self, Level, LevelFilter, Log, Metadata, Record};

struct SimpleLogger;

impl Log for SimpleLogger {
    fn enabled(&self, _metadata: &Metadata) -> bool {
        true
    }
    fn log(&self, record: &Record) {
        if !self.enabled(record.metadata()) {
            return;
        }
        let color = match record.level() {
            Level::Error => 31, // Red
            Level::Warn => 93,  // BrightYellow
            Level::Info => 34,  // Blue
            Level::Debug => 32, // Green
            Level::Trace => 90, // BrightBlack
        };
        println!(
            "\u{1B}[{}m[{:>5}] {}\u{1B}[0m",
            color,
            record.level(),
            record.args(),
        );
    }
    fn flush(&self) {}
}

pub fn init() {
    static LOGGER: SimpleLogger = SimpleLogger;
    log::set_logger(&LOGGER).unwrap();
    log::set_max_level(match option_env!("LOG") {
        Some("ERROR") => LevelFilter::Error,
        Some("WARN") => LevelFilter::Warn,
        Some("INFO") => LevelFilter::Info,
        Some("DEBUG") => LevelFilter::Debug,
        Some("TRACE") => LevelFilter::Trace,
        _ => LevelFilter::Info,
    });
}

use crate::drivers::bus::virtio::VirtioHal;
use crate::sync::UPIntrFreeCell;
use alloc::{sync::Arc, vec::Vec};
use core::any::Any;
use embedded_graphics::pixelcolor::Rgb888;
use log::warn;
use tinybmp::Bmp;
use virtio_drivers::{VirtIOGpu, VirtIOHeader};
const VIRTIO7: usize = 0x10007000;
pub trait GpuDevice: Send + Sync + Any {
    fn is_available(&self) -> bool;
    fn get_framebuffer(&self) -> &mut [u8];
    fn flush(&self);
}

lazy_static::lazy_static!(
    pub static ref GPU_DEVICE: Arc<dyn GpuDevice> = match VirtIOGpuWrapper::try_new() {
        Ok(gpu) => Arc::new(gpu),
        Err(()) => Arc::new(NullGpuDevice),
    };
);

pub struct VirtIOGpuWrapper {
    gpu: UPIntrFreeCell<VirtIOGpu<'static, VirtioHal>>,
    fb: &'static [u8],
}
static BMP_DATA: &[u8] = include_bytes!("../../assert/mouse.bmp");
impl VirtIOGpuWrapper {
    pub fn try_new() -> Result<Self, ()> {
        unsafe {
            let mut virtio = match VirtIOGpu::<VirtioHal>::new(&mut *(VIRTIO7 as *mut VirtIOHeader))
            {
                Ok(gpu) => gpu,
                Err(err) => {
                    warn!("GPU 初始化失败，已降级为无图形模式: {:?}", err);
                    return Err(());
                }
            };

            let fbuffer = match virtio.setup_framebuffer() {
                Ok(fbuffer) => fbuffer,
                Err(err) => {
                    warn!("GPU framebuffer 初始化失败，已降级为无图形模式: {:?}", err);
                    return Err(());
                }
            };
            let len = fbuffer.len();
            let ptr = fbuffer.as_mut_ptr();
            let fb = core::slice::from_raw_parts_mut(ptr, len);

            if let Ok(bmp) = Bmp::<Rgb888>::from_slice(BMP_DATA) {
                let raw = bmp.as_raw();
                let mut b = Vec::new();
                for i in raw.image_data().chunks(3) {
                    let mut v = i.to_vec();
                    b.append(&mut v);
                    if i == [255, 255, 255] {
                        b.push(0x0)
                    } else {
                        b.push(0xff)
                    }
                }
                if let Err(err) = virtio.setup_cursor(b.as_slice(), 50, 50, 50, 50) {
                    warn!("GPU cursor 初始化失败，继续使用无 cursor 模式: {:?}", err);
                }
            } else {
                warn!("GPU cursor 图片解析失败，继续使用无 cursor 模式");
            }

            Ok(Self {
                gpu: UPIntrFreeCell::new(virtio),
                fb,
            })
        }
    }
}

impl GpuDevice for VirtIOGpuWrapper {
    fn is_available(&self) -> bool {
        true
    }
    fn flush(&self) {
        if let Err(err) = self.gpu.exclusive_access().flush() {
            warn!("GPU flush 失败: {:?}", err);
        }
    }
    fn get_framebuffer(&self) -> &mut [u8] {
        unsafe {
            let ptr = self.fb.as_ptr() as *const _ as *mut u8;
            core::slice::from_raw_parts_mut(ptr, self.fb.len())
        }
    }
}

struct NullGpuDevice;

impl GpuDevice for NullGpuDevice {
    fn is_available(&self) -> bool {
        false
    }

    fn flush(&self) {
        warn!("GPU 不可用，忽略 framebuffer flush 请求");
    }

    fn get_framebuffer(&self) -> &mut [u8] {
        warn!("GPU 不可用，返回空 framebuffer");
        &mut []
    }
}

use alloc::format;
use core::fmt::{self, Write};
use core::sync::atomic::{AtomicBool, Ordering};

struct Stdout;

impl Write for Stdout {
    fn write_str(&mut self, s: &str) -> fmt::Result {
        for c in s.chars() {
            crate::arch::console_putchar(c as u8);
        }
        Ok(())
    }
}

static SCORE_OUTPUT_MODE: AtomicBool = AtomicBool::new(false);
static SCORE_DROP_USER_MARKER: AtomicBool = AtomicBool::new(false);
static SCORE_LAST_OUTPUT_NEWLINE: AtomicBool = AtomicBool::new(true);

pub fn set_score_output_mode(enable: bool) {
    SCORE_OUTPUT_MODE.store(enable, Ordering::SeqCst);
    SCORE_DROP_USER_MARKER.store(false, Ordering::SeqCst);
    SCORE_LAST_OUTPUT_NEWLINE.store(true, Ordering::SeqCst);
}

fn should_drop_score_text(s: &str) -> bool {
    let trimmed = s.trim_start_matches(|c| c == '\n' || c == '\r' || c == ' ');

    if s.contains("==========") {
        SCORE_DROP_USER_MARKER.store(false, Ordering::SeqCst);
        return true;
    }

    if SCORE_OUTPUT_MODE.load(Ordering::Relaxed) {
        if trimmed.starts_with("test_") {
            SCORE_DROP_USER_MARKER.store(true, Ordering::SeqCst);
            return true;
        }

        if SCORE_DROP_USER_MARKER.load(Ordering::Relaxed) {
            if s.contains('\n') || s.contains('\r') {
                SCORE_DROP_USER_MARKER.store(false, Ordering::SeqCst);
            }
            return true;
        }

        if trimmed.starts_with('[') {
            return true;
        }
    }

    false
}

pub fn score_should_drop_user_stdout(s: &str) -> bool {
    if !SCORE_OUTPUT_MODE.load(Ordering::Relaxed) {
        return false;
    }

    let trimmed = s.trim_start_matches(|c| c == '\n' || c == '\r' || c == ' ');

    if SCORE_DROP_USER_MARKER.load(Ordering::Relaxed) {
        if s.contains('\n') || s.contains('\r') {
            SCORE_DROP_USER_MARKER.store(false, Ordering::SeqCst);
        }
        return true;
    }

    if trimmed.starts_with('=') || s.contains("==========") {
        if !(s.contains('\n') || s.contains('\r')) {
            SCORE_DROP_USER_MARKER.store(true, Ordering::SeqCst);
        }
        return true;
    }

    if trimmed.starts_with("test_") {
        SCORE_DROP_USER_MARKER.store(true, Ordering::SeqCst);
        return true;
    }

    false
}

pub fn score_note_user_stdout(s: &str) {
    if SCORE_OUTPUT_MODE.load(Ordering::Relaxed) {
        let last_is_newline = s.ends_with('\n') || s.ends_with('\r');
        SCORE_LAST_OUTPUT_NEWLINE.store(last_is_newline, Ordering::SeqCst);
    }
}

fn raw_console_write_str(s: &str) {
    for c in s.chars() {
        crate::arch::console_putchar(c as u8);
    }
}

pub fn print_score_start(label: &str) {
    let line = format!("========== START {} ==========\n", label);
    Stdout.write_str(line.as_str()).unwrap();
}

pub fn print_score_end(label: &str) {
    if !SCORE_LAST_OUTPUT_NEWLINE.load(Ordering::Relaxed) {
        raw_console_write_str("\n");
    }
    let line = format!("========== END {} ==========\n", label);
    raw_console_write_str(line.as_str());
    SCORE_LAST_OUTPUT_NEWLINE.store(true, Ordering::SeqCst);
}
pub fn print(args: fmt::Arguments) {
    let text = format!("{}", args);
    if should_drop_score_text(text.as_str()) {
        return;
    }
    Stdout.write_str(text.as_str()).unwrap();
}

#[macro_export]
macro_rules! print {
    ($fmt: literal $(, $($arg: tt)+)?) => {
        $crate::console::print(format_args!($fmt $(, $($arg)+)?))
    }
}

#[macro_export]
macro_rules! println {
    ($fmt: literal $(, $($arg: tt)+)?) => {
        $crate::console::print(format_args!(concat!($fmt, "\n") $(, $($arg)+)?))
    }
}

use super::File;
use crate::drivers::chardev::CharDevice;
use crate::drivers::chardev::UART;
use crate::mm::UserBuffer;

pub struct Stdin;
pub struct Stdout;

impl File for Stdin {
    fn readable(&self) -> bool {
        true
    }
    fn writable(&self) -> bool {
        false
    }
    fn read(&self, mut user_buf: UserBuffer) -> usize {
        assert_eq!(user_buf.len(), 1);
        //println!("before UART.read() in Stdin::read()");
        let ch = UART.read();
        unsafe {
            user_buf.buffers[0].as_mut_ptr().write_volatile(ch);
        }
        1
    }
    fn write(&self, _user_buf: UserBuffer) -> usize {
        panic!("Cannot write to stdin!");
    }
}

impl File for Stdout {
    fn readable(&self) -> bool {
        false
    }
    fn writable(&self) -> bool {
        true
    }
    fn read(&self, _user_buf: UserBuffer) -> usize {
        panic!("Cannot read from stdout!");
    }
    fn write(&self, user_buf: UserBuffer) -> usize {
        for buffer in user_buf.buffers.iter() {
            if let Ok(text) = core::str::from_utf8(*buffer) {
                if crate::console::score_should_drop_user_stdout(text) {
                    continue;
                }
                for byte in buffer.iter() {
                    crate::arch::console_putchar(*byte);
                }
                crate::console::score_note_user_stdout(text);
            } else {
                for byte in buffer.iter() {
                    crate::arch::console_putchar(*byte);
                }
            }
        }
        user_buf.len()
    }
}

use super::File;
use crate::mm::UserBuffer;
use crate::sync::UPIntrFreeCell;
use alloc::sync::{Arc, Weak};

use crate::task::suspend_current_and_run_next;

pub struct Pipe {
    readable: bool,
    writable: bool,
    buffer: Arc<UPIntrFreeCell<PipeRingBuffer>>,
}

impl Pipe {
    pub fn read_end_with_buffer(buffer: Arc<UPIntrFreeCell<PipeRingBuffer>>) -> Self {
        Self {
            readable: true,
            writable: false,
            buffer,
        }
    }
    pub fn write_end_with_buffer(buffer: Arc<UPIntrFreeCell<PipeRingBuffer>>) -> Self {
        Self {
            readable: false,
            writable: true,
            buffer,
        }
    }
}

const RING_BUFFER_SIZE: usize = 32;

#[derive(Copy, Clone, PartialEq)]
enum RingBufferStatus {
    Full,
    Empty,
    Normal,
}

pub struct PipeRingBuffer {
    arr: [u8; RING_BUFFER_SIZE],
    head: usize,
    tail: usize,
    status: RingBufferStatus,
    read_end: Option<Weak<Pipe>>,
    write_end: Option<Weak<Pipe>>,
}

impl PipeRingBuffer {
    pub fn new() -> Self {
        Self {
            arr: [0; RING_BUFFER_SIZE],
            head: 0,
            tail: 0,
            status: RingBufferStatus::Empty,
            read_end: None,
            write_end: None,
        }
    }
    pub fn set_read_end(&mut self, read_end: &Arc<Pipe>) {
        self.read_end = Some(Arc::downgrade(read_end));
    }
    pub fn set_write_end(&mut self, write_end: &Arc<Pipe>) {
        self.write_end = Some(Arc::downgrade(write_end));
    }
    pub fn write_byte(&mut self, byte: u8) {
        self.status = RingBufferStatus::Normal;
        self.arr[self.tail] = byte;
        self.tail = (self.tail + 1) % RING_BUFFER_SIZE;
        if self.tail == self.head {
            self.status = RingBufferStatus::Full;
        }
    }
    pub fn read_byte(&mut self) -> u8 {
        self.status = RingBufferStatus::Normal;
        let c = self.arr[self.head];
        self.head = (self.head + 1) % RING_BUFFER_SIZE;
        if self.head == self.tail {
            self.status = RingBufferStatus::Empty;
        }
        c
    }
    pub fn available_read(&self) -> usize {
        if self.status == RingBufferStatus::Empty {
            0
        } else if self.tail > self.head {
            self.tail - self.head
        } else {
            self.tail + RING_BUFFER_SIZE - self.head
        }
    }
    pub fn available_write(&self) -> usize {
        if self.status == RingBufferStatus::Full {
            0
        } else {
            RING_BUFFER_SIZE - self.available_read()
        }
    }
    pub fn all_write_ends_closed(&self) -> bool {
        self.write_end.as_ref().unwrap().upgrade().is_none()
    }
    pub fn all_read_ends_closed(&self) -> bool {
        self.read_end.as_ref().unwrap().upgrade().is_none()
    }
}

/// Return (read_end, write_end)
pub fn make_pipe() -> (Arc<Pipe>, Arc<Pipe>) {
    let buffer = Arc::new(unsafe { UPIntrFreeCell::new(PipeRingBuffer::new()) });
    let read_end = Arc::new(Pipe::read_end_with_buffer(buffer.clone()));
    let write_end = Arc::new(Pipe::write_end_with_buffer(buffer.clone()));
    {
        let mut ring = buffer.exclusive_access();
        ring.set_read_end(&read_end);
        ring.set_write_end(&write_end);
    }
    (read_end, write_end)
}

impl File for Pipe {
    fn readable(&self) -> bool {
        self.readable
    }
    fn writable(&self) -> bool {
        self.writable
    }
    fn read(&self, buf: UserBuffer) -> usize {
        assert!(self.readable());
        let want_to_read = buf.len();
        let mut buf_iter = buf.into_iter();
        let mut already_read = 0usize;
        loop {
            let mut ring_buffer = self.buffer.exclusive_access();
            let loop_read = ring_buffer.available_read();
            if loop_read == 0 {
                if ring_buffer.all_write_ends_closed() {
                    return already_read;
                }
                drop(ring_buffer);
                suspend_current_and_run_next();
                continue;
            }
            for _ in 0..loop_read {
                if let Some(byte_ref) = buf_iter.next() {
                    unsafe {
                        *byte_ref = ring_buffer.read_byte();
                    }
                    already_read += 1;
                    if already_read == want_to_read {
                        return want_to_read;
                    }
                } else {
                    return already_read;
                }
            }
        }
    }
    fn write(&self, buf: UserBuffer) -> usize {
        assert!(self.writable());
        let want_to_write = buf.len();
        let mut buf_iter = buf.into_iter();
        let mut already_write = 0usize;
        loop {
            let mut ring_buffer = self.buffer.exclusive_access();
            if ring_buffer.all_read_ends_closed() {
                return already_write;
            }
            let loop_write = ring_buffer.available_write();
            if loop_write == 0 {
                drop(ring_buffer);
                suspend_current_and_run_next();
                continue;
            }
            // write at most loop_write bytes
            for _ in 0..loop_write {
                if let Some(byte_ref) = buf_iter.next() {
                    ring_buffer.write_byte(unsafe { *byte_ref });
                    already_write += 1;
                    if already_write == want_to_write {
                        return want_to_write;
                    }
                } else {
                    return already_write;
                }
            }
        }
    }
    fn pipe_read_end_closed(&self) -> bool {
        self.writable() && self.buffer.exclusive_access().all_read_ends_closed()
    }
}

