impl Ext4ShadowFile {
    pub fn new(path: &str, readable: bool, writable: bool, data: Vec<u8>) -> Self {
        Self {
            readable,
            writable,
            path: String::from(path),
            data,
            inner: unsafe { UPIntrFreeCell::new(Ext4ShadowFileInner { offset: 0 }) },
        }
    }

    fn read_to_slice(&self, out: &mut [u8]) -> usize {
        let mut inner = self.inner.exclusive_access();
        let old_offset = inner.offset;
        if old_offset >= self.data.len() {
            println!(
                "[read] ext4 shadow fd path={} offset={} len={} -> 0",
                self.path,
                old_offset,
                out.len()
            );
            return 0;
        }
        let read_len = core::cmp::min(out.len(), self.data.len() - old_offset);
        out[..read_len].copy_from_slice(&self.data[old_offset..old_offset + read_len]);
        inner.offset += read_len;
        println!(
            "[read] ext4 shadow fd path={} offset {} -> {} len={}",
            self.path, old_offset, inner.offset, read_len
        );
        read_len
    }
}

fn probe_filesystem_format() -> FileSystemFormat {
    let block_device = BLOCK_DEVICE.clone();
    let mut block = [0u8; BLOCK_SZ];

    block_device.read_block(0, &mut block);
    if u32::from_le_bytes(block[0..4].try_into().unwrap()) == EFS_MAGIC {
        return FileSystemFormat::EasyFs;
    }

    block_device.read_block(2, &mut block);
    if u16::from_le_bytes(block[56..58].try_into().unwrap()) == EXT4_SUPER_MAGIC {
        return FileSystemFormat::Ext4;
    }

    FileSystemFormat::Unknown
}

fn ext4_smoke_test() {
    println!("detected EXT4 filesystem");

    for path in ["/glibc/basic_testcode.sh", "/musl/basic_testcode.sh"].iter() {
        match read_file_by_path(path, 4096) {
            Ok(data) => {
                println!("EXT4 path read ok: {} len = {}", path, data.len());

                println!(
                    "EXT4 file preview = {}",
                    bytes_to_preview(&data[..core::cmp::min(data.len(), 256)])
                );
            }

            Err(err) => {
                println!("EXT4 path read failed: {} {:?}", path, err);

                shutdown_failure();
            }
        }
    }

    println!("[ext4] smoke test done, continue to runner");
}

lazy_static! {
    pub static ref ROOT_INODE: Arc<Inode> = {
        match probe_filesystem_format() {
            FileSystemFormat::EasyFs => {
                let efs = EasyFileSystem::open(BLOCK_DEVICE.clone());
                Arc::new(EasyFileSystem::root_inode(&efs))
            }

            FileSystemFormat::Ext4 => {
                panic!("EXT4 filesystem should be handled before ROOT_INODE access");
            }

            FileSystemFormat::Unknown => {
                panic!("unsupported filesystem format");
            }
        }
    };
}

fn bytes_to_preview(data: &[u8]) -> alloc::string::String {
    let mut preview = alloc::string::String::new();

    for byte in data.iter() {
        match *byte {
            b'\n' => preview.push('\n'),
            b'\r' => preview.push('\r'),
            b'\t' => preview.push('\t'),
            0x20..=0x7e => preview.push(*byte as char),
            _ => preview.push('.'),
        }
    }

    preview
}

pub fn list_apps() {
    match probe_filesystem_format() {
        FileSystemFormat::EasyFs => {
            println!("/**** APPS ****");
            for app in ROOT_INODE.ls() {
                println!("{}", app);
            }
            println!("**************/")
        }
        FileSystemFormat::Ext4 => {
            ext4_smoke_test();
        }
        FileSystemFormat::Unknown => {
            panic!("unsupported filesystem format");
        }
    }
}

