    match probe_filesystem_format() {
        FileSystemFormat::Ext4 => {
            let (readable, writable) = flags.read_write();
            match read_file_by_path(name, 16 * 1024 * 1024) {
                Ok(data) => {
                    println!(
                        "[openat] ext4 shadow fd open ok: {} bytes={}",
                        name,
                        data.len()
                    );
                    Some(Arc::new(Ext4ShadowFile::new(
                        name, readable, writable, data,
                    )))
                }
                Err(err) => {
                    println!("[openat] ext4 shadow fd open failed: {} {:?}", name, err);
                    None
                }
            }
        }
        FileSystemFormat::EasyFs => {
            open_file(name, flags).map(|inode| inode as Arc<dyn File + Send + Sync>)
        }
        FileSystemFormat::Unknown => None,
    }
}

