    unsafe extern "C" {
        static mut sbss: u8;
        static mut ebss: u8;
    }

    unsafe {
        let start = core::ptr::addr_of_mut!(sbss) as usize;
        let end = core::ptr::addr_of_mut!(ebss) as usize;
        let mut current = start as *mut u8;
        let end = end as *mut u8;
        while current < end {
            core::ptr::write_volatile(current, 0);
