fn print_hex(mut value: u64) {
    let mut buf = [0u8; 16];
    for i in (0..16).rev() {
        let digit = (value & 0xf) as u8;
        buf[i] = if digit < 10 {
            b'0' + digit
        } else {
            b'a' + digit - 10
        };
        value >>= 4;
    }
    puts("0x");
    for ch in &buf {
        uart_putchar(*ch);
    }
}

fn print_bytes(bytes: &[u8]) {
    for ch in bytes {
        match *ch {
            b'\n' => {
                uart_putchar(b'\\');
                uart_putchar(b'n');
            }
            b'\r' => {
                uart_putchar(b'\\');
                uart_putchar(b'r');
            }
            b'\t' => {
                uart_putchar(b'\\');
                uart_putchar(b't');
            }
            0x20..=0x7e => uart_putchar(*ch),
            _ => uart_putchar(b'.'),
        }
    }
}

